+// Sortable card component with drag handle
+interface SortableCardProps {
+  card: Card
+  onConfigure: () => void
+  onReplace: () => void
+  onRemove: () => void
+  isDragging: boolean
+}
+
+function SortableCard({ card, onConfigure, onReplace, onRemove, isDragging }: SortableCardProps) {
+  const {
+    attributes,
+    listeners,
+    setNodeRef,
+    transform,
+    transition,
+  } = useSortable({ id: card.id })
+
+  const style = {
+    transform: CSS.Transform.toString(transform),
+    transition,
+    gridColumn: `span ${card.position.w}`,
+    gridRow: `span ${card.position.h}`,
+    opacity: isDragging ? 0.5 : 1,
+  }
+
+  const CardComponent = CARD_COMPONENTS[card.card_type]
+
+  return (
+    <div ref={setNodeRef} style={style}>
+      <CardWrapper
+        cardId={card.id}
+        cardType={card.card_type}
+        lastSummary={card.last_summary}
+        title={card.title}
+        onConfigure={onConfigure}
+        onReplace={onReplace}
+        onRemove={onRemove}
+        dragHandle={
+          <button
+            {...attributes}
+            {...listeners}
+            className="p-1 rounded hover:bg-secondary cursor-grab active:cursor-grabbing"
+            title="Drag to reorder"
+          >
+            <GripVertical className="w-4 h-4 text-muted-foreground" />
+          </button>
+        }
+      >
+        {CardComponent ? (
+          <CardComponent config={card.config} />
+        ) : (
+          <div className="flex items-center justify-center h-full text-muted-foreground">
+            <p>Card type: {card.card_type}</p>
+          </div>
+        )}
+      </CardWrapper>
+    </div>
+  )
+}
+
